
-- Insert template for "Anamnese para Procedimentos Estéticos Dermatológicos"
INSERT INTO public.anamnesis_templates (
  id, name, description, specialty_id, clinic_id, template_type,
  is_system, is_default, is_active, icon, campos, created_at, updated_at
)
SELECT
  'd4e5f6a7-b8c9-4d0e-1f2a-3b4c5d6e7f80'::uuid,
  'Anamnese para Procedimentos Estéticos Dermatológicos',
  'Modelo clínico específico para avaliação pré-procedimento estético dermatológico, riscos, contraindicações, histórico e planejamento terapêutico.',
  s.id,
  s.clinic_id,
  'anamnese',
  true, false, true, 'Sparkles',
  '[]'::jsonb,
  now(), now()
FROM public.specialties s
WHERE s.name = 'Dermatologia' AND s.is_active = true
LIMIT 1
ON CONFLICT DO NOTHING;

